import { Ref, ref, watch } from 'vue'
import { CommissionRecord, SettlementRequest, SettlementResponse } from '../types'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

export type Filters = {
    promoterId: number | ''
    isSettled: boolean | ''
}

export type PromoterOption = {
    id: number
    userId: number
    userName?: string
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })
const makeFiltersRef = () => ref<Partial<Filters>>({ promoterId: '', isSettled: '' })

export const useCommissionRecords = (options?: { pagination?: Ref<Pagination>; filters?: Ref<Partial<Filters>> }) => {
    const isLoading = ref(false)
    const records = ref<CommissionRecord[]>([])
    const promoters = ref<PromoterOption[]>([])
    const users = ref<{ id: number; firstName?: string; lastName?: string; nickname?: string; email?: string }[]>([])

    const { filters = makeFiltersRef(), pagination = makePaginationRef() } = options || {}

    const getUserDisplayName = (userId: number): string => {
        const user = users.value.find((u) => u.id === userId)
        if (!user) return `User #${userId}`
        if (user.nickname) return user.nickname
        if (user.firstName || user.lastName) return `${user.firstName || ''} ${user.lastName || ''}`.trim()
        return user.email || `User #${userId}`
    }

    const fetchUsers = async () => {
        try {
            const { data } = await api.axiosInstance.get('/ops-user')
            users.value = data.data
        } catch (error) {
            console.error('Error fetching users:', error)
        }
    }

    const fetchPromoters = async () => {
        try {
            const { data } = await api.axiosInstance.get('/affiliate/promoter', { params: { limit: 100 } })
            const rawPromoters = data.data as PromoterOption[]
            promoters.value = rawPromoters.map((p) => ({
                ...p,
                userName: getUserDisplayName(p.userId),
            }))
        } catch (error) {
            console.error('Error fetching promoters:', error)
        }
    }

    const getPromoterName = (promoterId: number): string => {
        const promoter = promoters.value.find((p) => p.id === promoterId)
        return promoter?.userName || `Promoter #${promoterId}`
    }

    const fetch = async () => {
        isLoading.value = true
        try {
            const params: Record<string, unknown> = {
                page: pagination.value.page,
                limit: pagination.value.perPage,
            }
            if (filters.value.promoterId !== '') {
                params.promoterId = filters.value.promoterId
            }
            if (filters.value.isSettled !== '') {
                params.isSettled = filters.value.isSettled
            }

            const { data } = await api.axiosInstance.get('/affiliate/commission', { params })
            records.value = (data.data as CommissionRecord[]).map((r) => ({
                ...r,
                promoterName: getPromoterName(r.promoterId),
            }))
            ignoreUpdates(() => {
                pagination.value = {
                    page: pagination.value.page,
                    perPage: pagination.value.perPage,
                    total: data.total || data.data.length,
                }
            })
        } catch (error) {
            console.error('Error fetching commission records:', error)
        } finally {
            isLoading.value = false
        }
    }

    const { ignoreUpdates } = watchIgnorable([pagination], fetch, { deep: true })

    watch(
        filters,
        () => {
            pagination.value.page = 1
            fetch()
        },
        { deep: true },
    )

    const init = async () => {
        await fetchUsers()
        await fetchPromoters()
        await fetch()
    }

    init()

    const settle = async (request: SettlementRequest): Promise<SettlementResponse> => {
        if (!request.recordIds.length) {
            throw new Error('recordIds is required')
        }

        isLoading.value = true
        try {
            const payload: SettlementRequest = {
                promoterId: request.promoterId,
                recordIds: request.recordIds,
                note: request.note?.trim() || undefined,
                transferImage: request.transferImage || undefined,
            }

            const { data } = await api.axiosInstance.post('/affiliate/settlement', payload)
            await fetch()
            return data.data as SettlementResponse
        } finally {
            isLoading.value = false
        }
    }

    const uploadTransferImage = async (image: File): Promise<string> => {
        const formData = new FormData()
        formData.append('image', image)
        const response = await api.axiosInstance.post('/affiliate/settlement/transfer-image/upload', formData, {
            headers: {
                'Content-Type': 'multipart/form-data',
            },
        })
        return response.data.data.imageName as string
    }

    return {
        isLoading,
        filters,
        pagination,
        records,
        promoters,
        fetch,
        settle,
        uploadTransferImage,
    }
}
