<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import { useToast } from 'vuestic-ui'
import { CommissionStatus, CommissionStatusLabel } from './types'
import { useCommissionRecords } from './composables/useCommissionRecords'
import CommissionRecordsTable from './widgets/CommissionRecordsTable.vue'

const { records, isLoading, filters, pagination, promoters, settle, uploadTransferImage } = useCommissionRecords()
const { init: notify } = useToast()

const promoterFilterOptions = [{ value: '' as const, text: '全部推廣夥伴' }]

const settlementStatusOptions = [
    { value: '' as const, text: '全部' },
    { value: true, text: CommissionStatusLabel[CommissionStatus.Settled] },
    { value: false, text: CommissionStatusLabel[CommissionStatus.Unsettled] },
]

type PromoterSettlementSummary = {
    promoterId: number
    promoterName: string
    recordIds: number[]
    commissionRecordCount: number
    totalAmount: number
}

const showPromoterSelectModal = ref(false)
const showSettlementConfirmModal = ref(false)
const selectedPromoterId = ref<number | null>(null)
const settlementNote = ref('')
const transferImageFile = ref<File | undefined>(undefined)
const isSubmittingSettlement = ref(false)

const unsettledCurrentPageRecords = computed(() =>
    records.value.filter((record) => record.affiliateSettlementHistoryId === null),
)

const promoterSettlementSummaries = computed<PromoterSettlementSummary[]>(() => {
    const summaries = new Map<number, PromoterSettlementSummary>()

    unsettledCurrentPageRecords.value.forEach((record) => {
        const existing = summaries.get(record.promoterId)
        if (!existing) {
            summaries.set(record.promoterId, {
                promoterId: record.promoterId,
                promoterName: record.promoterName || `Promoter #${record.promoterId}`,
                recordIds: [record.id],
                commissionRecordCount: 1,
                totalAmount: Number(record.commissionAmount) || 0,
            })
            return
        }

        existing.recordIds.push(record.id)
        existing.commissionRecordCount += 1
        existing.totalAmount += Number(record.commissionAmount) || 0
    })

    return Array.from(summaries.values())
})

const promoterSelectionOptions = computed(() =>
    promoterSettlementSummaries.value.map((summary) => ({
        value: summary.promoterId,
        text: `${summary.promoterName}（${
            summary.commissionRecordCount
        } 筆 / VND ${summary.totalAmount.toLocaleString()}）`,
    })),
)

const selectedSettlementSummary = computed(
    () => promoterSettlementSummaries.value.find((summary) => summary.promoterId === selectedPromoterId.value) || null,
)

const noteError = computed(() => (settlementNote.value.length > 500 ? '備註最多 500 字' : ''))
const canPayCurrentPage = computed(() => unsettledCurrentPageRecords.value.length > 0)

const resetSettlementDraft = () => {
    selectedPromoterId.value = null
    settlementNote.value = ''
    transferImageFile.value = undefined
}

const openSettlementConfirmModal = () => {
    if (!canPayCurrentPage.value) {
        notify({ message: '當前頁沒有可支付的未支付佣金', color: 'warning' })
        return
    }

    if (promoterSettlementSummaries.value.length === 1) {
        selectedPromoterId.value = promoterSettlementSummaries.value[0].promoterId
        showSettlementConfirmModal.value = true
        return
    }

    selectedPromoterId.value = null
    showPromoterSelectModal.value = true
}

const proceedWithSelectedPromoter = () => {
    if (!selectedPromoterId.value) {
        notify({ message: '請先選擇要支付的推廣夥伴', color: 'warning' })
        return
    }

    showPromoterSelectModal.value = false
    showSettlementConfirmModal.value = true
}

const formatCurrency = (value: number) => `VND ${value.toLocaleString()}`

const submitSettlement = async () => {
    if (!selectedSettlementSummary.value) {
        notify({ message: '找不到可支付資料，請重新操作', color: 'danger' })
        return
    }

    if (noteError.value) {
        notify({ message: noteError.value, color: 'danger' })
        return
    }

    isSubmittingSettlement.value = true
    try {
        let imageName: string | undefined
        if (transferImageFile.value) {
            imageName = await uploadTransferImage(transferImageFile.value)
        }

        const result = await settle({
            promoterId: selectedSettlementSummary.value.promoterId,
            recordIds: selectedSettlementSummary.value.recordIds,
            note: settlementNote.value.trim() || undefined,
            transferImage: imageName,
        })

        notify({
            message: `支付完成：${result.commissionRecordCount} 筆，${formatCurrency(result.totalAmount)}`,
            color: 'success',
        })
        showSettlementConfirmModal.value = false
        resetSettlementDraft()
    } catch (error: any) {
        const message = error?.response?.data?.message || '支付失敗，請稍後再試'
        notify({ message, color: 'danger' })
    } finally {
        isSubmittingSettlement.value = false
    }
}

const closePromoterSelectModal = () => {
    showPromoterSelectModal.value = false
    selectedPromoterId.value = null
}

const closeSettlementConfirmModal = () => {
    showSettlementConfirmModal.value = false
    resetSettlementDraft()
}

watch(showPromoterSelectModal, (visible) => {
    if (!visible) {
        selectedPromoterId.value = null
    }
})

const transferImagePreviewUrl = computed(() =>
    transferImageFile.value ? URL.createObjectURL(transferImageFile.value) : null,
)

watch(showSettlementConfirmModal, (visible) => {
    if (!visible) {
        resetSettlementDraft()
    }
})
</script>

<template>
    <h1 class="page-title">優惠碼使用紀錄</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-4 justify-between flex-wrap">
                <div class="flex flex-col md:flex-row gap-2 justify-start flex-wrap">
                    <VaSelect
                        v-model="filters.promoterId"
                        :options="[
                            ...promoterFilterOptions,
                            ...promoters.map((p) => ({ value: p.id, text: p.userName || `Promoter #${p.id}` })),
                        ]"
                        value-by="value"
                        text-by="text"
                        placeholder="全部推廣夥伴"
                        class="w-48"
                    />
                    <VaSelect
                        v-model="filters.isSettled"
                        :options="settlementStatusOptions"
                        value-by="value"
                        text-by="text"
                        placeholder="佣金狀態"
                        class="w-40"
                    />
                </div>

                <VaButton
                    color="danger"
                    :disabled="!canPayCurrentPage || isLoading"
                    @click="openSettlementConfirmModal"
                >
                    支付佣金
                </VaButton>
            </div>

            <CommissionRecordsTable :records="records" :loading="isLoading" :pagination="pagination" />
        </VaCardContent>
    </VaCard>

    <VaModal v-model="showPromoterSelectModal" size="small" close-button hide-default-actions>
        <h3 class="va-h5 mb-4">選擇要支付的推廣夥伴</h3>

        <VaSelect
            v-model="selectedPromoterId"
            :options="promoterSelectionOptions"
            value-by="value"
            text-by="text"
            label="推廣夥伴"
            placeholder="請選擇推廣夥伴"
        />

        <div class="flex justify-end gap-2 mt-6">
            <VaButton preset="secondary" @click="closePromoterSelectModal">取消</VaButton>
            <VaButton color="danger" @click="proceedWithSelectedPromoter">下一步</VaButton>
        </div>
    </VaModal>

    <VaModal v-model="showSettlementConfirmModal" size="small" close-button hide-default-actions>
        <h3 class="va-h5 mb-4">確認支付佣金</h3>

        <div v-if="selectedSettlementSummary" class="space-y-4">
            <p class="text-sm text-secondary">
                您即將支付 {{ selectedSettlementSummary.commissionRecordCount }} 筆未支付的佣金記錄
            </p>

            <div class="rounded-lg bg-gray-100 px-4 py-3 flex justify-between items-center">
                <span class="font-medium text-secondary">總佣金金額：</span>
                <span class="text-2xl font-bold">{{ formatCurrency(selectedSettlementSummary.totalAmount) }}</span>
            </div>

            <p class="text-sm text-secondary">此操作無法復原，請確認後再進行支付。</p>

            <VaTextarea
                v-model="settlementNote"
                label="備註 (選填)"
                placeholder="輸入本次支付備註"
                :max-length="500"
                :error="Boolean(noteError)"
                :error-messages="noteError ? [noteError] : []"
                class="w-full"
            />

            <div class="w-full">
                <label class="va-input-label">轉帳截圖 (選填)</label>
                <VaFileUpload
                    v-model="transferImageFile"
                    type="single"
                    file-types="image/*"
                    hide-file-list
                    class="mt-1"
                >
                    <VaButton preset="secondary" size="small" icon="upload">上傳截圖</VaButton>
                </VaFileUpload>
                <div v-if="transferImageFile" class="mt-2 flex items-center gap-2">
                    <img
                        :src="transferImagePreviewUrl!"
                        alt="轉帳截圖預覽"
                        class="w-24 h-24 object-cover rounded border border-gray-300"
                    />
                    <VaButton
                        preset="primary"
                        color="danger"
                        size="small"
                        icon="delete"
                        @click="transferImageFile = undefined"
                    />
                </div>
            </div>

            <div class="flex justify-end gap-2">
                <VaButton preset="secondary" :disabled="isSubmittingSettlement" @click="closeSettlementConfirmModal">
                    取消
                </VaButton>
                <VaButton color="danger" :loading="isSubmittingSettlement" @click="submitSettlement">確認支付</VaButton>
            </div>
        </div>
    </VaModal>
</template>
