import { ServiceType, CommissionType } from '../coupons/types'

export { ServiceType, CommissionType }
export { ServiceTypeLabel } from '../coupons/types'

export const CommissionStatus = {
    Settled: 'settled',
    Unsettled: 'unsettled',
} as const

export type CommissionStatus = (typeof CommissionStatus)[keyof typeof CommissionStatus]

export const CommissionStatusLabel: Record<CommissionStatus, string> = {
    [CommissionStatus.Settled]: '已支付',
    [CommissionStatus.Unsettled]: '未支付',
}

export const CommissionStatusColor: Record<CommissionStatus, string> = {
    [CommissionStatus.Settled]: 'success',
    [CommissionStatus.Unsettled]: 'warning',
}

export type CommissionRecord = {
    createdAt: string
    updatedAt: string
    deletedAt: string | null
    id: number
    promoterId: number
    couponId: number
    couponCode: string
    orderId: number
    orderPaymentId: string
    serviceType: ServiceType
    commissionType: CommissionType
    commissionValue: number | string
    baseAmount: number | string
    orderTotalAmount: number | string
    commissionAmount: number | string
    peopleCount: number
    affiliateSettlementHistoryId: number | null
    user: {
        internalRemarkName: string | null
    }
    // joined
    promoterName?: string
}

export type SettlementRequest = {
    promoterId: number
    recordIds: number[]
    note?: string
    transferImage?: string
}

export type SettlementResponse = {
    id: number
    promoterId: number
    totalAmount: number
    affiliateCommissionRecordIds: number[]
    commissionRecordCount: number
    note: string
    operatorId: number
    createdAt: string
    updatedAt: string
}
