<script setup lang="ts">
import { defineVaDataTableColumns } from 'vuestic-ui'
import {
    CommissionRecord,
    CommissionType,
    CommissionStatus,
    CommissionStatusLabel,
    CommissionStatusColor,
    ServiceTypeLabel,
} from '../types'
import { PropType, computed } from 'vue'
import { Pagination } from '../composables/useCommissionRecords'
import { useFormat } from '../../../composables/useFormat'

const columns = defineVaDataTableColumns([
    { label: '訂單編號', key: 'orderId' },
    { label: '訂單日期', key: 'createdAt' },
    { label: '訂購人暱稱', key: 'internalRemarkName' },
    { label: '訂單類型', key: 'serviceType' },
    { label: '訂單金額', key: 'baseAmount' },
    { label: '推廣夥伴', key: 'promoterName' },
    { label: '優惠碼', key: 'couponCode' },
    { label: '佣金金額', key: 'commissionAmount' },
    { label: '退傭規則', key: 'commissionRule' },
    { label: '佣金狀態', key: 'status' },
])

const props = defineProps({
    records: {
        type: Array as PropType<CommissionRecord[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
})

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))

const getCommissionRule = (record: CommissionRecord): string => {
    if (record.commissionType === CommissionType.Percentage) {
        return `退佣${record.commissionValue}%`
    }
    return `固定金額`
}

const getStatus = (record: CommissionRecord): CommissionStatus => {
    return record.affiliateSettlementHistoryId !== null ? CommissionStatus.Settled : CommissionStatus.Unsettled
}

const { formatDateTime } = useFormat()
const formatDate = (timestamp: string): string => {
    if (!timestamp) return '-'
    return formatDateTime(Number(timestamp))
}
</script>

<template>
    <VaDataTable :columns="columns" :items="records" :loading="$props.loading">
        <template #cell(orderId)="{ rowData }">
            <span class="font-semibold">{{ rowData.orderId }}</span>
        </template>

        <template #cell(createdAt)="{ rowData }">
            {{ formatDate(rowData.createdAt) }}
        </template>

        <template #cell(serviceType)="{ rowData }">
            {{ ServiceTypeLabel[rowData.serviceType as keyof typeof ServiceTypeLabel] || rowData.serviceType }}
        </template>

        <template #cell(baseAmount)="{ rowData }"> VND {{ Number(rowData.baseAmount).toLocaleString() }} </template>

        <template #cell(internalRemarkName)="{ rowData }">
            <span>{{ rowData.user?.internalRemarkName || '-' }}</span>
        </template>

        <template #cell(promoterName)="{ rowData }">
            <div class="ellipsis max-w-[140px]">{{ rowData.promoterName }}</div>
        </template>

        <template #cell(couponCode)="{ rowData }">
            <span class="text-primary font-semibold">{{ rowData.couponCode }}</span>
        </template>

        <template #cell(commissionAmount)="{ rowData }">
            VND {{ Number(rowData.commissionAmount).toLocaleString() }}
        </template>

        <template #cell(commissionRule)="{ rowData }">
            {{ getCommissionRule(rowData as CommissionRecord) }}
        </template>

        <template #cell(status)="{ rowData }">
            <VaBadge
                :text="CommissionStatusLabel[getStatus(rowData as CommissionRecord)]"
                :color="CommissionStatusColor[getStatus(rowData as CommissionRecord)]"
            />
        </template>
    </VaDataTable>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect v-model="$props.pagination.perPage" class="!w-20" :options="[10, 50, 100]" />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="$props.pagination.page--"
            />
            <VaButton
                preset="secondary"
                icon="va-arrow-right"
                class="mr-2"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="$props.pagination.page++"
            />
            <VaPagination
                v-model="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
            />
        </div>
    </div>
</template>
